/**
 * TanStack Router factory. Must export `getRouter()` (the Start plugin
 * discovers it by name). `routeTree` is generated by the tanstackStart
 * Vite plugin from files under `src/routes/`.
 */

import {createRouter} from "@tanstack/react-router"

import {routeTree} from "./routeTree.gen"

export function getRouter(): ReturnType<typeof createRouter> {
    return createRouter({
        routeTree,
        scrollRestoration: true,
    })
}

declare module "@tanstack/react-router" {
    interface Register {
        router: ReturnType<typeof getRouter>
    }
}
